CREATE DEFINER=`root`@`localhost` PROCEDURE `Insert5000Data` ()   BEGIN
    DECLARE i INT DEFAULT 1;
    DECLARE v_cpu VARCHAR(50);
    DECLARE v_ram VARCHAR(50);
    DECLARE v_gpu VARCHAR(255);
    DECLARE v_ssd VARCHAR(50);
    DECLARE v_mh VARCHAR(255);
    DECLARE v_pin VARCHAR(255);
    DECLARE v_mau VARCHAR(50);
    DECLARE v_cn VARCHAR(10);

    WHILE i <= 5000 DO
        -- 1. Ngẫu nhiên CPU đa dạng (Intel & AMD)
        SET v_cpu = ELT(FLOOR(1 + RAND() * 8), 'i3 1215U', 'i5 12450H', 'i7 13700H', 'i9 13980HX', 'Ryzen 5 5500U', 'Ryzen 7 7735HS', 'Ryzen 9 7940HS', 'Ultra 5 125H');
        
        -- 2. Logic phối linh kiện: Máy mạnh thì GPU/RAM/Pin phải cao
        IF v_cpu LIKE '%i9%' OR v_cpu LIKE '%Ryzen 9%' THEN
            SET v_ram = ELT(FLOOR(1 + RAND() * 2), '32GB', '64GB');
            SET v_gpu = ELT(FLOOR(1 + RAND() * 2), 'RTX 4080 12GB', 'RTX 4090 16GB');
            SET v_mh = '16 inch QHD+ 240Hz';
            SET v_pin = '4-cell, 99Wh';
            SET v_cn = '2.5';
        ELSEIF v_cpu LIKE '%i7%' OR v_cpu LIKE '%Ryzen 7%' THEN
            SET v_ram = ELT(FLOOR(1 + RAND() * 2), '16GB', '32GB');
            SET v_gpu = ELT(FLOOR(1 + RAND() * 2), 'RTX 4060 8GB', 'RTX 4070 8GB');
            SET v_mh = ELT(FLOOR(1 + RAND() * 2), '15.6 inch 165Hz', '14.5 inch 2.8K OLED');
            SET v_pin = '4-cell, 75Wh';
            SET v_cn = '2.1';
        ELSEIF v_cpu LIKE '%i5%' OR v_cpu LIKE '%Ryzen 5%' THEN
            SET v_ram = ELT(FLOOR(1 + RAND() * 2), '8GB', '16GB');
            SET v_gpu = ELT(FLOOR(1 + RAND() * 2), 'Intel Iris Xe', 'RTX 3050');
            SET v_mh = '15.6 inch FHD 144Hz';
            SET v_pin = '3-cell, 57Wh';
            SET v_cn = '1.8';
        ELSE
            SET v_ram = '8GB';
            SET v_gpu = 'Intel UHD Graphics';
            SET v_mh = '14 inch FHD IPS';
            SET v_pin = '3-cell, 42Wh';
            SET v_cn = '1.4';
        END IF;

        -- 3. Random SSD, Màu sắc, Cổng kết nối
        SET v_ssd = ELT(FLOOR(1 + RAND() * 3), '256GB NVMe', '512GB NVMe', '1TB NVMe');
        SET v_mau = ELT(FLOOR(1 + RAND() * 5), 'Xám Titan', 'Đen Carbon', 'Bạc Platinum', 'Xanh Abyss', 'Trắng Ceramic');

        VALUES (i, v_ram, v_gpu, v_cpu, v_ssd, v_mh, v_pin, 'HDMI, Type-C, USB 3.2', v_mau, v_cn);

        SET i = i + 1;
    END WHILE;
END$$

